import { spawn } from 'child_process';
import path from 'path';
import { fileURLToPath } from 'url';
import fs from 'fs/promises';
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const projectRoot = path.join(__dirname, '..');
const COLORS = {
  reset: '\x1b[0m',
  bright: '\x1b[1m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m'
};
function colorize(color, text) {
  return `${COLORS[color]}${text}${COLORS.reset}`;
}
function log(message, color = 'reset') {
  console.log(colorize(color, message));
}
function error(message) {
  console.error(colorize('red', `❌ ${message}`));
}
function success(message) {
  console.log(colorize('green', `✅ ${message}`));
}
function info(message) {
  console.log(colorize('blue', `ℹ️  ${message}`));
}
function warning(message) {
  console.log(colorize('yellow', `⚠️  ${message}`));
}
async function runCommand(command, args, env = {}) {
  return new Promise((resolve, reject) => {
    const fullEnv = { ...process.env, ...env };
    const proc = spawn(command, args, {
      stdio: 'inherit',
      env: fullEnv,
      cwd: projectRoot
    });
    proc.on('close', (code) => {
      if (code === 0) {
        resolve();
      } else {
        reject(new Error(`Command failed with exit code ${code}`));
      }
    });
    proc.on('error', reject);
  });
}
import { getSecureTokenPath } from '../src/auth/paths.js';
async function loadTokens() {
  const tokenPath = getSecureTokenPath();
  try {
    const content = await fs.readFile(tokenPath, 'utf-8');
    return JSON.parse(content);
  } catch (error) {
    if (error.code === 'ENOENT') {
      return {};
    }
    throw error;
  }
}
async function listAccounts() {
  log('\n' + colorize('bright', '📋 Available Accounts:'));
  try {
    const tokens = await loadTokens();
    if (tokens.access_token || tokens.refresh_token) {
      log('  ' + colorize('yellow', '⚠️  Old token format detected. Will be migrated on next auth.'));
      const hasAccessToken = !!tokens.access_token;
      const hasRefreshToken = !!tokens.refresh_token;
      const isExpired = tokens.expiry_date ? Date.now() >= tokens.expiry_date : true;
      const status = hasAccessToken && hasRefreshToken && !isExpired ?
        colorize('green', '✓ Active') :
        hasRefreshToken ?
          colorize('yellow', '⟳ Needs Refresh') :
          colorize('red', '✗ Invalid');
      log(`  ${colorize('cyan', 'normal'.padEnd(10))} ${status} (legacy format)`);
      return;
    }
    const accounts = Object.keys(tokens);
    if (accounts.length === 0) {
      warning('No accounts found. Use "auth" command to authenticate.');
      return;
    }
    for (const account of accounts) {
      const tokenInfo = tokens[account];
      const hasAccessToken = !!tokenInfo.access_token;
      const hasRefreshToken = !!tokenInfo.refresh_token;
      const isExpired = tokenInfo.expiry_date ? Date.now() >= tokenInfo.expiry_date : true;
      const status = hasAccessToken && hasRefreshToken && !isExpired ?
        colorize('green', '✓ Active') :
        hasRefreshToken ?
          colorize('yellow', '⟳ Needs Refresh') :
          colorize('red', '✗ Invalid');
      log(`  ${colorize('cyan', account.padEnd(10))} ${status}`);
    }
  } catch (error) {
    error(`Failed to load token information: ${error.message}`);
  }
}
async function authenticateAccount(accountMode) {
  if (!['normal', 'test'].includes(accountMode)) {
    error('Account mode must be "normal" or "test"');
    process.exit(1);
  }
  log(`\n🔐 Authenticating ${colorize('cyan', accountMode)} account...`);
  try {
    await runCommand('npm', ['run', 'auth'], {
      GOOGLE_ACCOUNT_MODE: accountMode
    });
    success(`Successfully authenticated ${accountMode} account!`);
  } catch (error) {
    error(`Failed to authenticate ${accountMode} account: ${error.message}`);
    process.exit(1);
  }
}
async function showStatus() {
  log('\n' + colorize('bright', '📊 Account Status:'));
  const currentMode = process.env.GOOGLE_ACCOUNT_MODE || 'normal';
  log(`  Current Mode: ${colorize('cyan', currentMode)}`);
  await listAccounts();
  log('\n' + colorize('bright', '🧪 Test Configuration:'));
  const testVars = [
    'TEST_CALENDAR_ID',
    'INVITEE_1',
    'INVITEE_2',
    'CLAUDE_API_KEY'
  ];
  for (const varName of testVars) {
    const value = process.env[varName];
    if (value) {
      const displayValue = varName === 'CLAUDE_API_KEY' ?
        value.substring(0, 8) + '...' : value;
      log(`  ${varName.padEnd(20)}: ${colorize('green', displayValue)}`);
    } else {
      log(`  ${varName.padEnd(20)}: ${colorize('red', 'Not set')}`);
    }
  }
}
async function clearAccount(accountMode) {
  if (!['normal', 'test'].includes(accountMode)) {
    error('Account mode must be "normal" or "test"');
    process.exit(1);
  }
  log(`\n🗑️  Clearing ${colorize('cyan', accountMode)} account tokens...`);
  try {
    const tokens = await loadTokens();
    if (!tokens[accountMode]) {
      warning(`No tokens found for ${accountMode} account`);
      return;
    }
    delete tokens[accountMode];
    const tokenPath = getSecureTokenPath();
    if (Object.keys(tokens).length === 0) {
      await fs.unlink(tokenPath);
      success('All tokens cleared, file deleted');
    } else {
      await fs.writeFile(tokenPath, JSON.stringify(tokens, null, 2), { mode: 0o600 });
      success(`Cleared tokens for ${accountMode} account`);
    }
  } catch (error) {
    error(`Failed to clear ${accountMode} account: ${error.message}`);
    process.exit(1);
  }
}
async function runTests() {
  log('\n🧪 Running integration tests with test account...');
  try {
    await runCommand('npm', ['test'], {
      GOOGLE_ACCOUNT_MODE: 'test'
    });
    success('Tests completed successfully!');
  } catch (error) {
    error(`Tests failed: ${error.message}`);
    process.exit(1);
  }
}
function showUsage() {
  log('\n' + colorize('bright', 'Google Calendar Account Manager'));
  log('\nManage OAuth tokens for multiple Google accounts (normal & test)');
  log('\n' + colorize('bright', 'Usage:'));
  log('  node scripts/account-manager.js <command> [args]');
  log('\n' + colorize('bright', 'Commands:'));
  log('  list                    List available accounts and their status');
  log('  auth <normal|test>      Authenticate the specified account');
  log('  status                  Show current account status and configuration');
  log('  clear <normal|test>     Clear tokens for the specified account');
  log('  test                    Run integration tests with test account');
  log('  help                    Show this help message');
  log('\n' + colorize('bright', 'Examples:'));
  log('  node scripts/account-manager.js auth test     # Authenticate test account');
  log('  node scripts/account-manager.js test          # Run tests with test account');
  log('  node scripts/account-manager.js status        # Check account status');
  log('\n' + colorize('bright', 'Environment Variables:'));
  log('  GOOGLE_ACCOUNT_MODE     Set to "test" or "normal" (default: normal)');
  log('  TEST_CALENDAR_ID        Calendar ID to use for testing');
  log('  INVITEE_1, INVITEE_2    Email addresses for testing invitations');
  log('  CLAUDE_API_KEY          API key for Claude integration tests');
}
async function main() {
  const command = process.argv[2];
  const arg = process.argv[3];
  switch (command) {
    case 'list':
      await listAccounts();
      break;
    case 'auth':
      if (!arg) {
        error('Please specify account mode: normal or test');
        process.exit(1);
      }
      await authenticateAccount(arg);
      break;
    case 'status':
      await showStatus();
      break;
    case 'clear':
      if (!arg) {
        error('Please specify account mode: normal or test');
        process.exit(1);
      }
      await clearAccount(arg);
      break;
    case 'test':
      await runTests();
      break;
    case 'help':
    case '--help':
    case '-h':
      showUsage();
      break;
    default:
      if (command) {
        error(`Unknown command: ${command}`);
      }
      showUsage();
      process.exit(1);
  }
}
process.on('unhandledRejection', (reason, promise) => {
  error(`Unhandled rejection at: ${promise}, reason: ${reason}`);
  process.exit(1);
});
process.on('uncaughtException', (error) => {
  error(`Uncaught exception: ${error.message}`);
  process.exit(1);
});
main().catch((error) => {
  error(`Script failed: ${error.message}`);
  process.exit(1);
});#!/usr/bin/env node
import * as esbuild from 'esbuild';
import { fileURLToPath } from 'url';
import { dirname, join } from 'path';
const __dirname = dirname(fileURLToPath(import.meta.url));
const isWatch = process.argv.includes('--watch');
const buildOptions = {
  entryPoints: [join(__dirname, '../src/index.ts')],
  bundle: true,
  platform: 'node',
  target: 'node18',
  outfile: join(__dirname, '../build/index.js'),
  format: 'esm',
  banner: {
    js: '#!/usr/bin/env node\n',
  },
  packages: 'external',
  sourcemap: true,
};
const authServerBuildOptions = {
  entryPoints: [join(__dirname, '../src/auth-server.ts')],
  bundle: true,
  platform: 'node',
  target: 'node18',
  outfile: join(__dirname, '../build/auth-server.js'),
  format: 'esm',
  packages: 'external',
  sourcemap: true,
};
const verifyTokensBuildOptions = {
  entryPoints: [join(__dirname, '../src/verify-tokens.ts')],
  bundle: true,
  platform: 'node',
  target: 'node18',
  outfile: join(__dirname, '../build/verify-tokens.js'),
  format: 'esm',
  packages: 'external',
  sourcemap: true,
};
if (isWatch) {
  const context = await esbuild.context(buildOptions);
  const authContext = await esbuild.context(authServerBuildOptions);
  const verifyContext = await esbuild.context(verifyTokensBuildOptions);
  await Promise.all([context.watch(), authContext.watch(), verifyContext.watch()]);
  process.stderr.write('Watching for changes...\n');
} else {
  await Promise.all([
    esbuild.build(buildOptions),
    esbuild.build(authServerBuildOptions),
    esbuild.build(verifyTokensBuildOptions)
  ]);
  if (process.platform !== 'win32') {
    const { chmod } = await import('fs/promises');
    await chmod(buildOptions.outfile, 0o755);
  }
}#!/usr/bin/env node
/**
 * copypasta-check.mjs
 *
 * Recursively scans .mjs and .ts files and reports repeated code blocks.
 *
 * Usage:
 *   node copypasta-check.mjs [rootDir] [minLines]
 *
 * Examples:
 *   node copypasta-check.mjs .
 *   node copypasta-check.mjs src 8
 */

import fs from "node:fs";
import path from "node:path";
import crypto from "node:crypto";

const ROOT_DIR = path.resolve(process.argv[2] ?? ".");
const MIN_LINES = Number(process.argv[3] ?? 8);

const IGNORED_DIRS = new Set([
  "node_modules",
  ".git",
  "dist",
  "build",
  "coverage",
  ".next",
  ".turbo",
]);

function walk(dir) {
  const out = [];

  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const fullPath = path.join(dir, entry.name);

    if (entry.isDirectory()) {
      if (!IGNORED_DIRS.has(entry.name)) {
        out.push(...walk(fullPath));
      }
      continue;
    }

    if (entry.isFile() && (fullPath.endsWith(".mjs") || fullPath.endsWith(".ts"))) {
      out.push(fullPath);
    }
  }

  return out;
}

function stripInlineComment(line) {
  let inSingle = false;
  let inDouble = false;
  let inTemplate = false;
  let escaped = false;

  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    const next = line[i + 1];

    if (escaped) {
      escaped = false;
      continue;
    }

    if (ch === "\\") {
      escaped = true;
      continue;
    }

    if (!inDouble && !inTemplate && ch === "'" ) {
      inSingle = !inSingle;
      continue;
    }

    if (!inSingle && !inTemplate && ch === '"') {
      inDouble = !inDouble;
      continue;
    }

    if (!inSingle && !inDouble && ch === "`") {
      inTemplate = !inTemplate;
      continue;
    }

    if (!inSingle && !inDouble && !inTemplate && ch === "/" && next === "/") {
      return line.slice(0, i);
    }
  }

  return line;
}

function normalizeLines(content) {
  const rawLines = content.split(/\r?\n/);
  const normalized = [];
  const lineMap = [];

  let inBlockComment = false;

  for (let i = 0; i < rawLines.length; i++) {
    let line = rawLines[i];
    let out = "";
    let inSingle = false;
    let inDouble = false;
    let inTemplate = false;
    let escaped = false;

    for (let j = 0; j < line.length; j++) {
      const ch = line[j];
      const next = line[j + 1];

      if (inBlockComment) {
        if (ch === "*" && next === "/") {
          inBlockComment = false;
          j++;
        }
        continue;
      }

      if (escaped) {
        out += ch;
        escaped = false;
        continue;
      }

      if (ch === "\\") {
        out += ch;
        escaped = true;
        continue;
      }

      if (!inDouble && !inTemplate && ch === "'") {
        inSingle = !inSingle;
        out += ch;
        continue;
      }

      if (!inSingle && !inTemplate && ch === '"') {
        inDouble = !inDouble;
        out += ch;
        continue;
      }

      if (!inSingle && !inDouble && ch === "`") {
        inTemplate = !inTemplate;
        out += ch;
        continue;
      }

      if (!inSingle && !inDouble && !inTemplate && ch === "/" && next === "*") {
        inBlockComment = true;
        j++;
        continue;
      }

      out += ch;
    }

    out = stripInlineComment(out)
      .replace(/\s+/g, " ")
      .trim();

    if (out.length === 0) continue;
    if (out === "{" || out === "}" || out === ");" || out === "(" || out === ")") continue;

    normalized.push(out);
    lineMap.push(i + 1); // original 1-based line number
  }

  return { normalized, lineMap };
}

function hashBlock(lines) {
  return crypto.createHash("sha1").update(lines.join("\n")).digest("hex");
}

function makeBlocks(files, minLines) {
  const blocks = new Map();

  for (const file of files) {
    const content = fs.readFileSync(file, "utf8");
    const { normalized, lineMap } = normalizeLines(content);

    if (normalized.length < minLines) continue;

    for (let i = 0; i <= normalized.length - minLines; i++) {
      const slice = normalized.slice(i, i + minLines);
      const key = hashBlock(slice);

      if (!blocks.has(key)) {
        blocks.set(key, {
          block: slice,
          occurrences: [],
        });
      }

      blocks.get(key).occurrences.push({
        file,
        startLine: lineMap[i],
        endLine: lineMap[i + minLines - 1],
      });
    }
  }

  return blocks;
}

function summarizePairs(repeatedBlocks) {
  const pairScores = new Map();

  for (const entry of repeatedBlocks) {
    const uniqueOccurrences = dedupeOccurrences(entry.occurrences);

    for (let i = 0; i < uniqueOccurrences.length; i++) {
      for (let j = i + 1; j < uniqueOccurrences.length; j++) {
        const a = uniqueOccurrences[i];
        const b = uniqueOccurrences[j];

        if (a.file === b.file) continue;

        const pairKey = [a.file, b.file].sort().join(" :: ");
        pairScores.set(pairKey, (pairScores.get(pairKey) ?? 0) + 1);
      }
    }
  }

  return [...pairScores.entries()]
    .map(([pair, score]) => ({ pair, score }))
    .sort((a, b) => b.score - a.score);
}

function dedupeOccurrences(occurrences) {
  const seen = new Set();
  const out = [];

  for (const occ of occurrences) {
    const key = `${occ.file}:${occ.startLine}:${occ.endLine}`;
    if (!seen.has(key)) {
      seen.add(key);
      out.push(occ);
    }
  }

  return out;
}

function main() {
  if (!Number.isInteger(MIN_LINES) || MIN_LINES < 2) {
    console.error("minLines must be an integer >= 2");
    process.exit(1);
  }

  if (!fs.existsSync(ROOT_DIR) || !fs.statSync(ROOT_DIR).isDirectory()) {
    console.error(`Not a directory: ${ROOT_DIR}`);
    process.exit(1);
  }

  const files = walk(ROOT_DIR);

  if (files.length === 0) {
    console.log("No .mjs or .ts files found.");
    return;
  }

  const allBlocks = makeBlocks(files, MIN_LINES);

  const repeatedBlocks = [...allBlocks.values()]
    .map((entry) => ({
      ...entry,
      occurrences: dedupeOccurrences(entry.occurrences),
    }))
    .filter((entry) => entry.occurrences.length > 1)
    .sort((a, b) => b.occurrences.length - a.occurrences.length);

  console.log(`Scanned ${files.length} .mjs/.ts files under ${ROOT_DIR}`);
  console.log(`Window size: ${MIN_LINES} normalized lines`);
  console.log("");

  if (repeatedBlocks.length === 0) {
    console.log("No repeated blocks found.");
    return;
  }

  const pairScores = summarizePairs(repeatedBlocks);

  console.log("Most suspicious file pairs:");
  for (const { pair, score } of pairScores.slice(0, 15)) {
    console.log(`  ${score.toString().padStart(3)} shared blocks  ${pair}`);
  }

  console.log("");
  console.log("Repeated blocks:");
  console.log("");

  for (const [index, entry] of repeatedBlocks.slice(0, 50).entries()) {
    console.log(`#${index + 1}  repeated in ${entry.occurrences.length} places`);
    for (const occ of entry.occurrences) {
      console.log(`  - ${occ.file}:${occ.startLine}-${occ.endLine}`);
    }

    console.log("  snippet:");
    for (const line of entry.block.slice(0, Math.min(entry.block.length, 8))) {
      console.log(`    ${line}`);
    }
    console.log("");
  }

  if (repeatedBlocks.length > 50) {
    console.log(`...and ${repeatedBlocks.length - 50} more repeated blocks`);
  }
}

