                const isHidden = cal.hidden ? "Yes" : "No";
                const backgroundColor = this.sanitizeString(cal.backgroundColor || "Default");
                let description = "";
                if (cal.description) {
                    const sanitizedDesc = this.sanitizeString(cal.description);
                    description = sanitizedDesc.length > 100
