 * Date-based email filter utility
 * Abstracts logic for organizing emails by event date (past vs future)
 */
import { GMAIL_INBOX } from './constants.mjs';

/**
 * Parse event date from email content
 * Supports multiple date formats
 * @param {string} content - Email subject or body text
 * @returns {Date|null} Parsed date or null if not found
 */
export function extractEventDate(content) {
  if (!content) return null;

  const today = new Date();
  const currentYear = today.getFullYear();

  const months = {
    jan: 0, january: 0,
    feb: 1, february: 1,
    mar: 2, march: 2,
    apr: 3, april: 3,
    may: 4,
    jun: 5, june: 5,
    jul: 6, july: 6,
    aug: 7, august: 7,
    sep: 8, september: 8,
    oct: 9, october: 9,
    nov: 10, november: 10,
    dec: 11, december: 11
  };

  // Try ISO format: 2026-03-25 or 2026/03/25
  let match = content.match(/(\d{4})[-\/](\d{1,2})[-\/](\d{1,2})/);
  if (match) {
    const year = parseInt(match[1]);
    const month = parseInt(match[2]) - 1;
    const day = parseInt(match[3]);
    if (month >= 0 && month <= 11 && day >= 1 && day <= 31) {
      return new Date(year, month, day);
    }
  }

  // Try MM/DD/YYYY or MM-DD-YYYY
  match = content.match(/(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})/);
  if (match) {
    const month = parseInt(match[1]) - 1;
    const day = parseInt(match[2]);
    const year = parseInt(match[3]);
    if (month >= 0 && month <= 11 && day >= 1 && day <= 31) {
      return new Date(year, month, day);
    }
  }

  // Try M/D or MM/DD (assume current or next year)
  match = content.match(/(?:^|\s)(\d{1,2})\/(\d{1,2})(?:\s|$)/);
  if (match) {
    const month = parseInt(match[1]) - 1;
    const day = parseInt(match[2]);
    if (month >= 0 && month <= 11 && day >= 1 && day <= 31) {
      let year = currentYear;
      // If month/day has passed, assume next year
      const testDate = new Date(year, month, day);
      if (testDate < today) {
        year = currentYear + 1;
      }
      return new Date(year, month, day);
    }
  }

  // Try "Month Day, Year" or "Month Day" formats
  match = content.match(/([A-Za-z]+)\s+(\d{1,2}),?\s+(\d{4})?/);
  if (match) {
    const monthStr = match[1];
    const day = parseInt(match[2]);
    const year = match[3] ? parseInt(match[3]) : currentYear;
    const monthIndex = months[monthStr.toLowerCase().substring(0, 3)];

    if (monthIndex !== undefined && day >= 1 && day <= 31) {
      return new Date(year, monthIndex, day);
    }
  }

  // Try "Day Mon DD" format: "@ Mon, Mar 23" or "@ Fri 25"
  match = content.match(/(?:@\s+)?(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun),?\s+([A-Za-z]+)?\s+(\d{1,2})/i);
  if (match) {
    const monthStr = match[1];
    const day = parseInt(match[2]);

    if (monthStr) {
      const monthIndex = months[monthStr.toLowerCase().substring(0, 3)];
      if (monthIndex !== undefined && day >= 1 && day <= 31) {
        let year = currentYear;
        const testDate = new Date(year, monthIndex, day);
        if (testDate < today) {
          year = currentYear + 1;
        }
        return new Date(year, monthIndex, day);
      }
    }
  }

  return null;
}

/**
 * Determine if event is in the past
 * @param {Date|null} eventDate - Event date (null if unknown)
 * @returns {boolean|null} true if past, false if future, null if unknown
 */
export function isPastEvent(eventDate) {
  if (!eventDate) return null;

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const normalized = new Date(eventDate);
  normalized.setHours(0, 0, 0, 0);

  return normalized < today;
}

/**
 * Classify email by event recency
 * @param {string} emailSubject - Email subject line
 * @param {string} emailBody - Email body content
 * @returns {object} Classification result
 *   - status: 'future' | 'past' | 'unknown'
 *   - eventDate: Date|null
 *   - reason: string (explanation)
 */
export function classifyEmail(emailSubject, emailBody) {
  // Try to extract date from subject first, then body
  const eventDate = extractEventDate(emailSubject) || extractEventDate(emailBody);

  if (!eventDate) {
    return {
      status: 'unknown',
      eventDate: null,
      reason: 'Could not parse event date'
    };
  }

  const isPast = isPastEvent(eventDate);
  const dateStr = eventDate.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric'
  });

  if (isPast) {
    return {
      status: 'past',
      eventDate,
      reason: `Event was ${dateStr}`
    };
  }

  return {
    status: 'future',
    eventDate,
    reason: `Event is ${dateStr}`
  };
}

/**
 * Determine Gmail actions based on email classification
 * @param {string} status - Classification status ('future' | 'past' | 'unknown')
 * @param {string} futureLabel - Label ID to apply to future events
 * @param {boolean} archivePast - Whether to archive past events (default: true)
 * @returns {object} Gmail API action object
 *   - addLabelIds: [label IDs to add]
 *   - removeLabelIds: [label IDs to remove]
 */
export function getGmailAction(status, futureLabel, archivePast = true) {
  const action = {
    addLabelIds: futureLabel ? [futureLabel] : [],
    removeLabelIds: []
  };

  if (status === 'past' && archivePast) {
    action.removeLabelIds.push(GMAIL_INBOX);
  }

  return action;
}

/**
 * Process a batch of emails with date-based filtering
 * @param {object[]} emails - Array of email objects with id, subject, body
 * @param {string} futureLabel - Label ID for future events
 * @param {boolean} archivePast - Whether to archive past events
 * @returns {object} Results with categorized emails
 *   - future: [email ids]
 *   - past: [email ids]
 *   - unknown: [email ids]
 *   - classifications: [email classifications]
 */
export function classifyEmails(emails, futureLabel, archivePast = true) {
  const results = {
    future: [],
    past: [],
    unknown: [],
    classifications: []
  };

  for (const email of emails) {
    const classification = classifyEmail(email.subject, email.body);
    classification.id = email.id;
    classification.action = getGmailAction(classification.status, futureLabel, archivePast);

    results.classifications.push(classification);
    results[classification.status].push(email.id);
  }

  return results;
}import { EmailMessageSchema, EmailCategorySchema, PrintSectionConfigSchema, EmailSubsectionSchema } from '../src/schemas/email-analyzer-types.ts';

const SECTION_DIVIDER = '═'.repeat(80);
const ROW_DIVIDER = '─'.repeat(76);

const DEFAULT_SCORE = 5;
const HIGH_SCORE = 9;
const LOW_SCORE = 2;
const HIGH_THRESHOLD = 7;
const LOW_THRESHOLD = 3;

const HIGH_URGENCY_KEYWORDS = ['urgent', 'asap', 'immediate', 'critical', 'emergency', 'alert'];
const LOW_URGENCY_KEYWORDS = ['fyi', 'newsletter', 'digest', 'weekly', 'monthly', 'notification'];
const HIGH_IMPORTANCE_KEYWORDS = ['manager', 'boss', 'ceo', 'invoice', 'payment', 'contract', 'approved', 'rejected', 'decision'];
const LOW_IMPORTANCE_KEYWORDS = ['marketing', 'promotion', 'sale', 'discount', 'follow', 'subscribe'];

/**
 * Score content against keyword lists
 * @param {string} content - Text to score
 * @param {string[]} highKeywords - Keywords indicating high score
 * @param {string[]} lowKeywords - Keywords indicating low score
 * @returns {number} Score value (2, 5, or 9)
 */
export function scoreContent(content, highKeywords, lowKeywords) {
  if (highKeywords.some(k => content.includes(k))) return HIGH_SCORE;
  if (lowKeywords.some(k => content.includes(k))) return LOW_SCORE;
  return DEFAULT_SCORE;
}

/**
 * Categorize an email by urgency and importance
 * @param {Object} msg - Email message object
 * @returns {Object} Categorization with urgency and importance levels
 */
export function categorizeEmail(msg) {
  const validated = EmailMessageSchema.parse(msg);
  const subject = validated.subject.toLowerCase();
  const from = validated.from.toLowerCase();
  const snippet = validated.snippet.toLowerCase();
  const content = `${subject} ${from} ${snippet}`;

  const urgencyScore = scoreContent(content, HIGH_URGENCY_KEYWORDS, LOW_URGENCY_KEYWORDS);
  const importanceScore = scoreContent(content, HIGH_IMPORTANCE_KEYWORDS, LOW_IMPORTANCE_KEYWORDS);

  const urgency = urgencyScore >= HIGH_THRESHOLD ? 'High' : (urgencyScore <= LOW_THRESHOLD ? 'Low' : 'Medium');
  const importance = importanceScore >= HIGH_THRESHOLD ? 'High' : (importanceScore <= LOW_THRESHOLD ? 'Low' : 'Medium');

  return EmailCategorySchema.parse({ urgency, importance });
}

/**
 * Print email subsections with configurable truncation
 * @param {string} title - Section title
 * @param {Object[]} subsections - Email subsections with labels and emails
 * @param {Object} displayConfig - Display configuration (fromMax, subjectMax, snippetMax)
 */
export function printSection(title, subsections, displayConfig = {}) {
  const config = PrintSectionConfigSchema.parse(displayConfig);
  const { fromMax, subjectMax, snippetMax } = config;

  // Validate subsections
  subsections.forEach(s => EmailSubsectionSchema.parse(s));

  const hasContent = subsections.some(s => s.emails.length > 0);
  if (!hasContent) return;

  console.log(`\n${title}`);
  console.log(SECTION_DIVIDER + "\n");

  subsections.forEach(({ label, emails, limit, count }) => {
    if (emails.length === 0) return;

    console.log(`  ${label}`);
    console.log('  ' + ROW_DIVIDER);

    if (count) {
      console.log(`  ${emails.length} promotional/newsletter emails\n`);
      return;
    }

    emails.slice(0, limit || Infinity).forEach((email, idx) => {
      console.log(`  ${idx + 1}. 👤 ${email.from.substring(0, fromMax)}`);
      console.log(`     📌 ${email.subject.substring(0, subjectMax)}`);
      console.log(`     📝 ${email.snippet.substring(0, snippetMax)}...`);
      console.log();
    });

    if (limit && emails.length > limit) {
      console.log(`  ... and ${emails.length - limit} more\n`);
    }
  });
}

