import { USER_ID, LABEL_NEWSLETTERS } from './lib/constants.mjs';
import { buildLabelCache } from './lib/gmail-label-utils.mjs';

async function organizeNewsletters() {
  const gmail = createGmailClient();

  console.log('📧 ORGANIZING NEWSLETTERS\n');
  const labelCache = await buildLabelCache(gmail);
  const newsletterLabelId = labelCache.get(LABEL_NEWSLETTERS);
  if (!newsletterLabelId) {
    console.error('Newsletters label not found');
    process.exit(1);
  }
  console.log('═'.repeat(80));

  console.log('\n1️⃣  APPLYING LABEL TO EXISTING NEWSLETTERS\n');

  const newsletterPatterns = [
    'from:news@alphasignal.ai',
    'from:noreply@email.openai.com',
    'from:hello@adapty.io',
    'from:info@email.meetup.com',
    'from:googlecloud@google.com',
    'from:communications@yodlee.com',
    'from:updates-noreply@linkedin.com',
    'from:noreply@notifications.hubspot.com',
    'from:support@substack.com',
    'subject:newsletter OR subject:digest OR subject:weekly OR subject:monthly',
    'label:Promotions',
  ];

  let totalLabeled = 0;

  for (const query of newsletterPatterns) {
    try {
      const searchResult = await gmail.users.messages.list({
        userId: USER_ID,
        q: query,
        maxResults: 100,
      });

      if (!searchResult.data.messages) continue;

      const messageIds = searchResult.data.messages.map(m => m.id);
      const count = messageIds.length;

      if (count > 0) {
        await gmail.users.messages.batchModify({
          userId: USER_ID,
          requestBody: {
            ids: messageIds,
            addLabelIds: [newsletterLabelId],
          },
        });

        console.log(`  ✅ Applied to ${count} emails matching: "${query}"`);
        totalLabeled += count;
      }
    } catch (error) {
      console.log(`  ⚠️  Error processing "${query}": ${error.message}`);
    }
  }

  console.log(`\n  📊 Total labeled: ${totalLabeled} emails\n`);

  console.log('═'.repeat(80));
  console.log('\n2️⃣  CREATING AUTO-LABEL FILTER FOR FUTURE NEWSLETTERS\n');

  const filters = [
    {
      name: 'AlphaSignal News',
      criteria: { from: 'news@alphasignal.ai' },
      action: { addLabelIds: [newsletterLabelId], archive: false }
    },
    {
      name: 'OpenAI Newsletter',
      criteria: { from: 'noreply@email.openai.com' },
      action: { addLabelIds: [newsletterLabelId], archive: false }
    },
    {
      name: 'Adapty Updates',
      criteria: { from: 'hello@adapty.io' },
      action: { addLabelIds: [newsletterLabelId], archive: false }
    },
    {
      name: 'Meetup Notifications',
      criteria: { from: 'info@email.meetup.com' },
      action: { addLabelIds: [newsletterLabelId], archive: false }
    },
    {
      name: 'Google Cloud Updates',
      criteria: { from: 'googlecloud@google.com' },
      action: { addLabelIds: [newsletterLabelId], archive: false }
    },
    {
      name: 'Promotional Emails',
      criteria: { query: 'label:Promotions' },
      action: { addLabelIds: [newsletterLabelId], archive: false }
    },
  ];

  let filtersCreated = 0;

  for (const filterConfig of filters) {
    try {
      const response = await gmail.users.settings.filters.create({
        userId: USER_ID,
        requestBody: {
          criteria: filterConfig.criteria,
          action: {
            addLabelIds: filterConfig.action.addLabelIds,
          },
        },
      });

      console.log(`  ✅ Filter created: ${filterConfig.name}`);
      console.log(`     ID: ${response.data.id}\n`);
      filtersCreated++;
    } catch (error) {
      if (error.message.includes('exists')) {
        console.log(`  ℹ️  Filter already exists: ${filterConfig.name}`);
      } else {
        console.log(`  ⚠️  Error creating filter "${filterConfig.name}": ${error.message}`);
      }
    }
  }

  console.log('═'.repeat(80));
  console.log('\n✨ NEWSLETTER ORGANIZATION COMPLETE\n');
  console.log(`  📌 Labeled existing emails: ${totalLabeled}`);
  console.log(`  🔄 Filters created: ${filtersCreated}`);
  console.log('\n💡 Newsletter emails will now be automatically labeled going forward!');
}

organizeNewsletters().catch(error => {
  console.error('❌ Error:', error.message);
  process.exit(1);
});import { createGmailClient } from './lib/gmail-client.mjs';
import { USER_ID, LABEL_KEEP_IMPORTANT } from './lib/constants.mjs';

async function protectImportantItems() {
  const gmail = createGmailClient();

  console.log('⭐ PROTECTING IMPORTANT ITEMS IN INBOX\n');
  console.log('═'.repeat(80) + '\n');

  let importantLabelId;
  const labelsResponse = await gmail.users.labels.list({ userId: USER_ID });
  const existingLabel = labelsResponse.data.labels.find(l => l.name === LABEL_KEEP_IMPORTANT);

  if (existingLabel) {
    importantLabelId = existingLabel.id;
    console.log('✅ Using existing label: Keep Important\n');
  } else {
    const createLabelResponse = await gmail.users.labels.create({
      userId: USER_ID,
      requestBody: {
        name: LABEL_KEEP_IMPORTANT,
        labelListVisibility: 'labelShow',
        messageListVisibility: 'show'
      }
    });
    importantLabelId = createLabelResponse.data.id;
    console.log('✅ Created label: Keep Important\n');
  }

  const importantFilters = [
    {
      name: 'Cloudflare Alerts',
      query: 'from:noreply@notify.cloudflare.com'
    },
    {
      name: 'Calendly Refunds & Support',
      query: 'from:(support@calendly.zendesk.com OR invoice+statements@calendly.com) OR subject:(refund OR "Added to a team")'
    },
    {
      name: 'Investment Banking Meetings',
      query: 'from:notification@calendly.com subject:"Introductory Meeting"'
    },
    {
      name: 'Capital City Village Services',
      query: 'from:(capitalcity@a.helpfulvillage.com OR info@capitalcityvillage.org)'
    }
  ];

  console.log('STEP 1: Creating filters to keep important items in inbox\n');

  for (const config of importantFilters) {
    try {
      await gmail.users.settings.filters.create({
        userId: USER_ID,
        requestBody: {
          criteria: {
            query: config.query
          },
          action: {
            addLabelIds: [importantLabelId]
            // Note: NOT removing INBOX label - this keeps them visible
          }
        }
      });
      console.log(`  ✅ ${config.name}`);
      console.log(`     Query: ${config.query}\n`);
    } catch (error) {
      console.log(`  ⚠️  ${config.name}: ${error.message}\n`);
    }
  }

  console.log('STEP 2: Labeling existing important emails\n');

  const queryCounts = await Promise.all(
    importantFilters.map(async ({ query }) => {
      const searchResponse = await gmail.users.messages.list({
        userId: USER_ID,
        q: query,
        maxResults: 100
      });

      const messageIds = searchResponse.data.messages || [];
      if (messageIds.length === 0) return 0;

      const batchSize = 50;
      for (let i = 0; i < messageIds.length; i += batchSize) {
        const batch = messageIds.slice(i, i + batchSize);
        await gmail.users.messages.batchModify({
          userId: USER_ID,
          requestBody: {
            ids: batch.map(m => m.id),
            addLabelIds: [importantLabelId]
          }
        });
      }

      return messageIds.length;
    })
  );

  const totalLabeled = queryCounts.reduce((sum, n) => sum + n, 0);

  console.log(`  ✅ Labeled ${totalLabeled} important emails\n`);

  console.log('═'.repeat(80));
  console.log('COMPLETE\n');
  console.log('Protected items (will stay in inbox):');
  console.log('  • Cloudflare alerts (action required)');
  console.log('  • Calendly refunds & support');
  console.log('  • Investment Banking meeting reminders');
  console.log('  • Capital City Village service requests\n');
  console.log('All labeled with: Keep Important ⭐\n');
  console.log('═'.repeat(80) + '\n');
}

protectImportantItems().catch(error => {
  console.error('❌ Error:', error.message);
  process.exit(1);
