  if (!text) return null;
  const patterns = [
    new RegExp(`${RESPONSE_PATTERNS.LEGACY_CREATED}.* \\(([^)]+)\\)`),
    new RegExp(`${RESPONSE_PATTERNS.LEGACY_UPDATED}.* \\(([^)]+)\\)`),
    new RegExp(`${RESPONSE_INDICATORS.SUCCESS_CHECK} ${RESPONSE_PATTERNS.NEW_CREATED}[\\s\\S]*?([^\\s\\(]+) \\(([^)]+)\\)`),
    new RegExp(`${RESPONSE_INDICATORS.SUCCESS_CHECK} ${RESPONSE_PATTERNS.NEW_UPDATED}[\\s\\S]*?([^\\s\\(]+) \\(([^)]+)\\)`),
    new RegExp(`${RESPONSE_PATTERNS.EVENT_ID_PREFIX}([^\\s]+)`),
    new RegExp(`${RESPONSE_PATTERNS.CREATED_EVENT}.* \\(${RESPONSE_PATTERNS.ID_SUFFIX}([^)]+)\\)`),
    new RegExp(`\\((${RESPONSE_PATTERNS.EVENT_ID_CHAR_CLASS}{${EVENT_ID_MIN_LENGTH},})\\)`)
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      let eventId = match[match.length - 1] || match[1];
      if (eventId) {
        eventId = eventId.trim();
        if (eventId.length >= EVENT_ID_MIN_LENGTH) {
          return eventId;
        }
      }
    }
  }
  return null;
}import { describe, it, expect, vi } from 'vitest';
