describe('EventSimilarityChecker', () => {
  const checker = new EventSimilarityChecker();
  describe('checkSimilarity', () => {
    it('should return 0.95 for identical events', () => {
      const event1 = makeTeamMeetingEvent();
      const event2 = { ...event1 };
      const similarity = checker.checkSimilarity(event1, event2);
      expect(similarity).toBe(0.95);
    });
    it('should detect high similarity for events with same title and time', () => {
      const event1 = makeTeamMeetingEvent();
      const event2 = makeTeamMeetingEvent('Conference Room B');
      const similarity = checker.checkSimilarity(event1, event2);
      expect(similarity).toBeGreaterThan(0.8);
    });
    it('should detect moderate similarity for events with similar titles', () => {
      const event1 = makeTeamMeetingEvent();
      const event2 = makeEvent({
        summary: 'Team Meeting Discussion',
        start: { dateTime: '2024-01-01T14:00:00' },
        end: { dateTime: '2024-01-01T15:00:00' }
      });
      const similarity = checker.checkSimilarity(event1, event2);
      expect(similarity).toBe(0.3);
    });
    it('should detect low similarity for completely different events', () => {
      const event1 = makeTeamMeetingEvent();
      const event2 = makeEvent({
        summary: 'Doctor Appointment',
        location: 'Medical Center',
        start: { dateTime: '2024-02-15T09:00:00' },
        end: { dateTime: '2024-02-15T09:30:00' }
      });
      const similarity = checker.checkSimilarity(event1, event2);
      expect(similarity).toBeLessThan(0.3);
    });
    it('should handle events with missing fields', () => {
      const event1 = makeEvent({
        summary: 'Meeting',
        start: { dateTime: '2024-01-01T10:00:00' },
        end: { dateTime: '2024-01-01T11:00:00' }
      });
      const event2 = makeEvent({
        location: 'Room 101',
        start: { dateTime: '2024-01-01T10:00:00' },
        end: { dateTime: '2024-01-01T11:00:00' }
      });
      const similarity = checker.checkSimilarity(event1, event2);
      expect(similarity).toBeGreaterThan(0);
      expect(similarity).toBeLessThan(0.5);
    });
    it('should handle all-day events', () => {
      const event1 = makeEvent({
        summary: 'Conference',
        start: { date: '2024-01-01' },
        end: { date: '2024-01-02' }
      });
      const event2 = makeEvent({
        summary: 'Conference',
        start: { date: '2024-01-01' },
        end: { date: '2024-01-02' }
      });
      const similarity = checker.checkSimilarity(event1, event2);
      expect(similarity).toBe(0.95);
    });
  });
  describe('all-day vs timed events', () => {
    it('should not treat all-day event as duplicate of timed event with same title', () => {
      const allDayEvent = makeEvent({
        summary: 'Conference',
        start: { date: '2024-01-15' },
        end: { date: '2024-01-16' }
      });
      const timedEvent = makeEvent({
        summary: 'Conference',
        start: { dateTime: '2024-01-15T09:00:00' },
        end: { dateTime: '2024-01-15T17:00:00' }
      });
      const similarity = checker.checkSimilarity(allDayEvent, timedEvent);
      expect(similarity).toBeLessThanOrEqual(0.3);
      expect(checker.isDuplicate(allDayEvent, timedEvent)).toBe(false);
    });
    it('should not treat timed event as duplicate of all-day event', () => {
      const timedEvent = makeTeamMeetingEvent('Mountain View', {
        summary: 'Team Offsite',
        start: { dateTime: '2024-01-15T10:00:00' },
        end: { dateTime: '2024-01-15T15:00:00' }
      });
      const allDayEvent = makeEvent({
        summary: 'Team Offsite',
        location: 'Mountain View',
        start: { date: '2024-01-15' },
        end: { date: '2024-01-16' }
      });
      const similarity = checker.checkSimilarity(timedEvent, allDayEvent);
      expect(similarity).toBeLessThanOrEqual(0.3);
      expect(checker.isDuplicate(timedEvent, allDayEvent, 0.7)).toBe(false);
    });
    it('should still detect duplicates between two all-day events', () => {
      const allDay1 = makeEvent({
        summary: 'Company Holiday',
        start: { date: '2024-07-04' },
        end: { date: '2024-07-05' }
      });
      const allDay2 = makeEvent({
        summary: 'Company Holiday',
        start: { date: '2024-07-04' },
        end: { date: '2024-07-05' }
      });
      const similarity = checker.checkSimilarity(allDay1, allDay2);
      expect(similarity).toBe(0.95);
      expect(checker.isDuplicate(allDay1, allDay2)).toBe(true);
    });
    it('should still detect duplicates between two timed events', () => {
      const timed1 = makeEvent({
        summary: 'Sprint Planning',
        start: { dateTime: '2024-01-15T10:00:00' },
        end: { dateTime: '2024-01-15T12:00:00' }
      });
      const timed2 = makeEvent({
        summary: 'Sprint Planning',
        start: { dateTime: '2024-01-15T10:00:00' },
        end: { dateTime: '2024-01-15T12:00:00' }
      });
      const similarity = checker.checkSimilarity(timed1, timed2);
      expect(similarity).toBe(0.95);
      expect(checker.isDuplicate(timed1, timed2)).toBe(true);
    });
    it('should handle common patterns like OOO/vacation', () => {
      const allDayOOO = makeEvent({
        summary: 'John OOO',
        start: { date: '2024-01-15' },
        end: { date: '2024-01-16' }
      });
      const timedMeeting = makeEvent({
        summary: 'Meeting with John',
        start: { dateTime: '2024-01-15T14:00:00' },
        end: { dateTime: '2024-01-15T15:00:00' }
      });
      const similarity = checker.checkSimilarity(allDayOOO, timedMeeting);
      expect(similarity).toBeLessThan(0.3);
      expect(checker.isDuplicate(allDayOOO, timedMeeting)).toBe(false);
    });
  });
  describe('isDuplicate', () => {
    it('should identify duplicates above threshold', () => {
      const event1 = makeTeamMeetingEvent();
      const event2 = makeTeamMeetingEvent();
      expect(checker.isDuplicate(event1, event2)).toBe(true);
      expect(checker.isDuplicate(event1, event2, 0.9)).toBe(true);
      expect(checker.isDuplicate(event1, event2, 0.96)).toBe(false);
    });
    it('should not identify non-duplicates as duplicates', () => {
      const event1 = makeTeamMeetingEvent();
      const event2 = makeEvent({
        summary: 'Different Meeting',
        start: { dateTime: '2024-01-02T14:00:00' },
        end: { dateTime: '2024-01-02T15:00:00' }
      });
      expect(checker.isDuplicate(event1, event2)).toBe(false);
      expect(checker.isDuplicate(event1, event2, 0.5)).toBe(false);
    });
  });
});import { createGmailClient } from './lib/gmail-client.mjs';
import { USER_ID, LABEL_NEWSLETTERS_CCV } from './lib/constants.mjs';
import { getHeader } from './lib/email-utils.mjs';
import { buildLabelCache } from './lib/gmail-label-utils.mjs';

async function analyzeCCVNewsletter() {
  const gmail = createGmailClient();

  console.log('📊 ANALYZING CCV NEWSLETTER EMAILS\n');
  console.log('═'.repeat(80) + '\n');

  const labelCache = await buildLabelCache(gmail);
  const labelId = labelCache.get(LABEL_NEWSLETTERS_CCV);
  if (!labelId) {
    console.log('Newsletters/CCV label not found');
    return;
  }
  const messagesResult = await gmail.users.messages.list({
    userId: USER_ID,
    labelIds: [labelId],
    maxResults: 100,
  });

  if (!messagesResult.data.messages) {
    console.log('No CCV newsletter emails found');
    return;
  }

  console.log(`📧 Found ${messagesResult.data.messages.length} CCV Newsletter emails\n`);
  console.log('═'.repeat(80) + '\n');

  const fullMsgs = await Promise.all(
    messagesResult.data.messages.map(msgHeader =>
      gmail.users.messages.get({
        userId: USER_ID,
        id: msgHeader.id,
        format: 'metadata',
        metadataHeaders: ['Subject', 'From', 'Date'],
      }).catch(error => {
        console.log(`Error fetching message: ${error.message}`);
        return null;
      })
    )
  );

  const messages = fullMsgs
    .filter(Boolean)
    .map(msg => {
      const headers = msg.data.payload.headers || [];
      return {
        subject: getHeader(headers, 'Subject', '(no subject)'),
        from: getHeader(headers, 'From', '(unknown)'),
        date: getHeader(headers, 'Date', '(no date)'),
      };
    });

  console.log('📋 CCV NEWSLETTER EMAILS\n');

  messages.sort((a, b) => {
    const dateA = new Date(a.date);
    const dateB = new Date(b.date);
    return dateB - dateA;
  });

  const emailsByMonth = {};

  for (const msg of messages) {
    const dateObj = new Date(msg.date);
    const monthKey = `${dateObj.getFullYear()}-${String(dateObj.getMonth() + 1).padStart(2, '0')}`;

    if (!emailsByMonth[monthKey]) {
      emailsByMonth[monthKey] = [];
    }
    emailsByMonth[monthKey].push(msg);
  }

  for (const [monthKey, emails] of Object.entries(emailsByMonth)) {
    const [year, month] = monthKey.split('-');
    const monthName = new Date(year, month - 1).toLocaleString('default', { month: 'long', year: 'numeric' });

    console.log(`${monthName.toUpperCase()}`);
    console.log(`Count: ${emails.length}\n`);

    for (const email of emails) {
      const truncated = email.subject.length > 75
        ? email.subject.substring(0, 75) + '...'
        : email.subject;
      console.log(`  • ${truncated}`);
    }
    console.log();
  }

  console.log('═'.repeat(80) + '\n');
  console.log('📋 CONTENT ANALYSIS\n');

  const categories = {
    'Funding/Startup News': 0,
    'Industry Updates': 0,
    'Community News': 0,
    'Career/Jobs': 0,
    'Tech/Innovation': 0,
    'Events': 0,
    'Reports/Analysis': 0,
    'Other': 0,
  };

  const categoryPatterns = {
    'Funding/Startup News': /fund|startup|funding|investment|investor|raise|series|valuation/i,
    'Industry Updates': /industry|market|trend|analysis|report/i,
    'Community News': /community|event|conference|meetup|gather/i,
    'Career/Jobs': /job|career|hiring|recruit|opportunity|position/i,
    'Tech/Innovation': /tech|ai|innovation|software|platform|tool/i,
    'Events': /event|summit|workshop|webinar|conference/i,
    'Reports/Analysis': /report|analysis|insight|data|survey|study/i,
  };

  for (const msg of messages) {
    let categorized = false;
    for (const [category, pattern] of Object.entries(categoryPatterns)) {
      if (pattern.test(msg.subject)) {
        categories[category]++;
        categorized = true;
        break;
      }
    }
    if (!categorized) {
      categories['Other']++;
    }
  }

  console.log('📊 SUBJECT CATEGORY DISTRIBUTION\n');
  const sortedCategories = Object.entries(categories)
    .filter(([_, count]) => count > 0)
    .sort((a, b) => b[1] - a[1]);

  for (const [category, count] of sortedCategories) {
    const percentage = ((count / messages.length) * 100).toFixed(1);
    console.log(`${category}: ${count} (${percentage}%)`);
  }

  console.log('\n' + '═'.repeat(80));
  console.log('\n💡 INSIGHTS\n');
  console.log(`Total CCV Newsletters: ${messages.length}`);
  console.log(`Date Range: ${messages[messages.length - 1]?.date} to ${messages[0]?.date}`);
  console.log('\nThe CCV Newsletter appears to be a curated roundup of community news,');
  console.log('covering startup funding, industry trends, and technology updates.');
}

