        'EXDATE:20240610T100000Z',
        'EXDATE:20240612T100000Z'
      ];
      expect(() => helpers.updateRecurrenceWithUntil(recurrence, UNTIL_DATE))
        .toThrow('No RRULE found in recurrence rules');
