        'EXDATE;TZID=America/Los_Angeles:20250704T130500',
        'EXDATE;TZID=America/Los_Angeles:20250707T130500',
        'RRULE:FREQ=WEEKLY;BYDAY=MO,WE,FR;UNTIL=20251102T210500Z',
        'EXDATE;TZID=America/Los_Angeles:20250709T130500',
