export class SearchEventsHandler extends BaseToolHandler {
    async runTool(args: any, oauth2Client: OAuth2Client): Promise<CallToolResult> {
        const validArgs = args as SearchEventsInput;
        const events = await this.searchEvents(oauth2Client, validArgs);
        if (events.length === 0) {
            return this.textResult("No events found matching your search criteria.");
        }
        const eventsWithCalendarId = events.map(event => ({
            ...event,
            calendarId: validArgs.calendarId
        }));
        const text = formatEventsList(eventsWithCalendarId);
        return this.textResult(text);
    }
    private async searchEvents(
        client: OAuth2Client,
        args: SearchEventsInput
    ): Promise<calendar_v3.Schema$Event[]> {
        try {
            const calendar = this.getCalendar(client);
            const timezone = args.timeZone || await this.getCalendarTimezone(client, args.calendarId);
            const { timeMin, timeMax } = resolveTimeRange(args.timeMin, args.timeMax, timezone);
            const fieldMask = buildListFieldMask(args.fields);
            const response = await calendar.events.list({
                calendarId: args.calendarId,
                q: args.query,
                timeMin,
                timeMax,
                singleEvents: true,
                orderBy: 'startTime',
                ...(fieldMask && { fields: fieldMask }),
                ...(args.privateExtendedProperty && { privateExtendedProperty: args.privateExtendedProperty }),
                ...(args.sharedExtendedProperty && { sharedExtendedProperty: args.sharedExtendedProperty })
            });
            return response.data.items || [];
        } catch (error) {
            throw this.handleGoogleApiError(error);
        }
    }
}import { OAuth2Client } from "google-auth-library";
import { google, calendar_v3 } from "googleapis";
import {
  ConflictCheckResult,
  ConflictInfo,
  DuplicateInfo,
  ConflictDetectionOptions
} from "./types.js";
import { EventSimilarityChecker } from "./EventSimilarityChecker.js";
import { ConflictAnalyzer } from "./ConflictAnalyzer.js";
import { CONFLICT_DETECTION_CONFIG } from "./config.js";
import { getEventUrl } from "../../handlers/utils.js";
import {
  resolveTimeRange,
  hasTimezoneInDatetime,
  resolveTimeZone,
  isValidIANATimeZone
} from "../../utils/timezone-utils.js";
function getEventDateTime(event: calendar_v3.Schema$Event): { start?: string; end?: string } {
  return {
    start: event.start?.dateTime || event.start?.date || undefined,
    end: event.end?.dateTime || event.end?.date || undefined,
  };
}
function formatEventTimesForInfo(event: calendar_v3.Schema$Event): { start?: string; end?: string } {
  return {
    start: event.start?.dateTime || event.start?.date || undefined,
    end: event.end?.dateTime || event.end?.date || undefined,
  };
}
export class ConflictDetectionService {
  private similarityChecker: EventSimilarityChecker;
  private conflictAnalyzer: ConflictAnalyzer;
  constructor() {
    this.similarityChecker = new EventSimilarityChecker();
    this.conflictAnalyzer = new ConflictAnalyzer();
  }
  async checkConflicts(
    oauth2Client: OAuth2Client,
    event: calendar_v3.Schema$Event,
    calendarId: string,
    options: ConflictDetectionOptions = {}
  ): Promise<ConflictCheckResult> {
    const {
      checkDuplicates = true,
      checkConflicts = true,
      calendarsToCheck = [calendarId],
      duplicateSimilarityThreshold = CONFLICT_DETECTION_CONFIG.DEFAULT_DUPLICATE_THRESHOLD,
      includeDeclinedEvents = false
    } = options;
    const result: ConflictCheckResult = {
      hasConflicts: false,
      conflicts: [],
      duplicates: []
    };
    if (!event.start || !event.end) {
      return result;
    }
    const { start: timeMin, end: timeMax } = getEventDateTime(event);
    if (!timeMin || !timeMax) {
      return result;
    }
    const rawTimezone = event.start?.timeZone || event.end?.timeZone;
    const timezone = rawTimezone && isValidIANATimeZone(rawTimezone)
      ? rawTimezone
      : undefined;
    const needsConversion = timezone && timeMin && !hasTimezoneInDatetime(timeMin);
    let searchTimeMin: string | undefined = timeMin;
    let searchTimeMax: string | undefined = timeMax;
    if (needsConversion) {
      const timeRange = resolveTimeRange(timeMin!, timeMax!, timezone!);
      searchTimeMin = timeRange.timeMin;
      searchTimeMax = timeRange.timeMax;
    }
    for (const checkCalendarId of calendarsToCheck) {
      try {
        if (!searchTimeMin || !searchTimeMax) {
          continue;
        }
        const events = await this.getEventsInTimeRange(
          oauth2Client,
          checkCalendarId,
          searchTimeMin,
          searchTimeMax,
          timezone || undefined
        );
        if (checkDuplicates) {
          const duplicates = this.findDuplicates(
            event,
            events,
            checkCalendarId,
            duplicateSimilarityThreshold
          );
          result.duplicates.push(...duplicates);
        }
        if (checkConflicts) {
          const conflicts = this.findConflicts(
            event,
            events,
            checkCalendarId,
            includeDeclinedEvents
          );
          result.conflicts.push(...conflicts);
        }
      } catch (error) {
      }
    }
    result.hasConflicts = result.conflicts.length > 0 || result.duplicates.length > 0;
    return result;
  }
  private async getEventsInTimeRange(
    oauth2Client: OAuth2Client,
    calendarId: string,
    timeMin: string,
    timeMax: string,
    timeZone?: string
  ): Promise<calendar_v3.Schema$Event[]> {
    const calendar = google.calendar({ version: "v3", auth: oauth2Client });
    const listParams: any = {
      calendarId,
      timeMin,
      timeMax,
      singleEvents: true,
      orderBy: 'startTime',
      maxResults: 250
    };
    if (timeZone) {
      listParams.timeZone = timeZone;
    }
    const response = await calendar.events.list(listParams);
    const events = response?.data?.items || [];
    return events;
  }
  private findDuplicates(
    newEvent: calendar_v3.Schema$Event,
    existingEvents: calendar_v3.Schema$Event[],
    calendarId: string,
    threshold: number
  ): DuplicateInfo[] {
    const duplicates: DuplicateInfo[] = [];
    for (const existingEvent of existingEvents) {
      if (existingEvent.id === newEvent.id) continue;
      if (existingEvent.status === 'cancelled') continue;
      const similarity = this.similarityChecker.checkSimilarity(newEvent, existingEvent);
      if (similarity >= threshold) {
        duplicates.push({
          event: {
            id: existingEvent.id!,
            title: existingEvent.summary || 'Untitled Event',
            url: getEventUrl(existingEvent, calendarId) || undefined,
            similarity: Math.round(similarity * 100) / 100
          },
          fullEvent: existingEvent,
          calendarId: calendarId,
          suggestion: similarity >= CONFLICT_DETECTION_CONFIG.DUPLICATE_THRESHOLDS.BLOCKING
            ? 'This appears to be a duplicate. Consider updating the existing event instead.'
            : 'This event is very similar to an existing one. Is this intentional?'
        });
      }
    }
    return duplicates;
  }
  private findConflicts(
    newEvent: calendar_v3.Schema$Event,
    existingEvents: calendar_v3.Schema$Event[],
    calendarId: string,
    includeDeclinedEvents: boolean
  ): ConflictInfo[] {
    const conflicts: ConflictInfo[] = [];
    const overlappingEvents = this.conflictAnalyzer.findOverlappingEvents(existingEvents, newEvent);
    for (const conflictingEvent of overlappingEvents) {
      if (!includeDeclinedEvents && this.isEventDeclined(conflictingEvent)) {
        continue;
      }
      const overlap = this.conflictAnalyzer.analyzeOverlap(newEvent, conflictingEvent);
      if (overlap.hasOverlap) {
        const { start, end } = formatEventTimesForInfo(conflictingEvent);
        conflicts.push({
          type: 'overlap',
          calendar: calendarId,
          event: {
            id: conflictingEvent.id!,
            title: conflictingEvent.summary || 'Untitled Event',
            url: getEventUrl(conflictingEvent, calendarId) || undefined,
            start,
            end
          },
          fullEvent: conflictingEvent,
          overlap: {
            duration: overlap.duration!,
            percentage: overlap.percentage!,
            startTime: overlap.startTime!,
            endTime: overlap.endTime!
          }
        });
      }
    }
    return conflicts;
  }
  private isEventDeclined(_event: calendar_v3.Schema$Event): boolean {
    return false;
  }
  async checkConflictsWithFreeBusy(
    oauth2Client: OAuth2Client,
    eventToCheck: calendar_v3.Schema$Event,
    calendarsToCheck: string[]
  ): Promise<ConflictInfo[]> {
    const conflicts: ConflictInfo[] = [];
    if (!eventToCheck.start || !eventToCheck.end) return conflicts;
    const { start: timeMin, end: timeMax } = getEventDateTime(eventToCheck);
    if (!timeMin || !timeMax) return conflicts;
    const calendar = google.calendar({ version: "v3", auth: oauth2Client });
    try {
      const freeBusyResponse = await calendar.freebusy.query({
        requestBody: {
          timeMin,
          timeMax,
          items: calendarsToCheck.map(id => ({ id }))
        }
      });
      for (const [calendarId, calendarInfo] of Object.entries(freeBusyResponse.data.calendars || {})) {
        if (calendarInfo.busy && calendarInfo.busy.length > 0) {
          for (const busySlot of calendarInfo.busy) {
            if (this.conflictAnalyzer.checkBusyConflict(eventToCheck, busySlot)) {
              conflicts.push({
                type: 'overlap',
                calendar: calendarId,
                event: {
                  id: 'busy-time',
                  title: 'Busy (details unavailable)',
                  start: busySlot.start || undefined,
                  end: busySlot.end || undefined
                }
              });
            }
          }
        }
      }
    } catch (error) {
      console.error('Failed to check free/busy:', error);
    }
    return conflicts;
  }
