import { BaseToolHandler } from "./BaseToolHandler.js";
import { calendar_v3 } from 'googleapis';
import { RecurringEventHelpers, RecurringEventError, RECURRING_EVENT_ERRORS } from './RecurringEventHelpers.js';
import { createEventResponseWithConflicts } from "../utils.js";
import { ConflictDetectionService } from "../../services/conflict-detection/index.js";
import { createTimeObject } from "../../utils/timezone-utils.js";
import {
  buildEventForConflictCheckUpdate,
  performConflictCheck,
} from "./eventManipulationUtils.js";
export class UpdateEventHandler extends BaseToolHandler {
    private conflictDetectionService: ConflictDetectionService;
    constructor() {
        super();
        this.conflictDetectionService = new ConflictDetectionService();
    }
    async runTool(args: any, oauth2Client: OAuth2Client): Promise<CallToolResult> {
        const validArgs = args as UpdateEventInput;
        let conflicts = null;
        if (validArgs.checkConflicts !== false && (validArgs.start || validArgs.end)) {
            const calendar = this.getCalendar(oauth2Client);
            const existingEvent = await calendar.events.get({
                calendarId: validArgs.calendarId,
                eventId: validArgs.eventId
            });
            if (!existingEvent.data) {
                throw new Error('Event not found');
            }
            const timezone = validArgs.timeZone || await this.getCalendarTimezone(oauth2Client, validArgs.calendarId);
            const eventToCheck = buildEventForConflictCheckUpdate(validArgs, existingEvent.data, timezone);
            conflicts = await performConflictCheck(
                this.conflictDetectionService,
                oauth2Client,
                eventToCheck,
                validArgs.calendarId,
                {
                    checkDuplicates: false,
                    checkConflicts: true,
                    calendarsToCheck: validArgs.calendarsToCheck || [validArgs.calendarId],
                }
            );
        }
        const event = await this.updateEventWithScope(oauth2Client, validArgs);
        const text = createEventResponseWithConflicts(event, validArgs.calendarId, conflicts ?? undefined, "updated");
        return this.textResult(text);
    }
    private async updateEventWithScope(
        client: OAuth2Client,
        args: UpdateEventInput
    ): Promise<calendar_v3.Schema$Event> {
        try {
            const calendar = this.getCalendar(client);
            const helpers = new RecurringEventHelpers(calendar);
            const defaultTimeZone = await this.getCalendarTimezone(client, args.calendarId);
            const { event, type: eventType } = await helpers.getEventAndType(args.eventId, args.calendarId);
            if (args.modificationScope && args.modificationScope !== 'all' && eventType !== 'recurring') {
                throw new RecurringEventError(
                    'Scope other than "all" only applies to recurring events',
                    RECURRING_EVENT_ERRORS.NON_RECURRING_SCOPE
                );
            }
            switch (args.modificationScope) {
                case 'thisEventOnly':
                    return this.updateSingleInstance(helpers, args, defaultTimeZone);
                case 'all':
                case undefined:
                    return this.updateAllInstances(helpers, args, defaultTimeZone);
                case 'thisAndFollowing':
                    return this.updateFutureInstances(helpers, args, defaultTimeZone, event);
                default:
                    throw new RecurringEventError(
                        `Invalid modification scope: ${args.modificationScope}`,
                        RECURRING_EVENT_ERRORS.INVALID_SCOPE
                    );
            }
        } catch (error) {
            if (error instanceof RecurringEventError) {
                throw error;
            }
            throw this.handleGoogleApiError(error);
        }
    }
    private async updateSingleInstance(
        helpers: RecurringEventHelpers,
        args: UpdateEventInput,
        defaultTimeZone: string
    ): Promise<calendar_v3.Schema$Event> {
        if (!args.originalStartTime) {
            throw new RecurringEventError(
                'originalStartTime is required for single instance updates',
                RECURRING_EVENT_ERRORS.MISSING_ORIGINAL_TIME
            );
        }
        const calendar = helpers.getCalendar();
        const instanceId = helpers.formatInstanceId(args.eventId, args.originalStartTime);
        const response = await calendar.events.patch({
            calendarId: args.calendarId,
            eventId: instanceId,
            requestBody: helpers.buildUpdateRequestBody(args, defaultTimeZone)
        });
        if (!response.data) throw new Error('Failed to update event instance');
        return response.data;
    }
    private async updateAllInstances(
        helpers: RecurringEventHelpers,
        args: UpdateEventInput,
        defaultTimeZone: string
    ): Promise<calendar_v3.Schema$Event> {
        const calendar = helpers.getCalendar();
        const response = await calendar.events.patch({
            calendarId: args.calendarId,
            eventId: args.eventId,
            requestBody: helpers.buildUpdateRequestBody(args, defaultTimeZone)
        });
        if (!response.data) throw new Error('Failed to update event');
        return response.data;
    }
    private async updateFutureInstances(
        helpers: RecurringEventHelpers,
        args: UpdateEventInput,
        defaultTimeZone: string,
        originalEvent?: calendar_v3.Schema$Event
    ): Promise<calendar_v3.Schema$Event> {
        if (!args.futureStartDate) {
            throw new RecurringEventError(
                'futureStartDate is required for future instance updates',
                RECURRING_EVENT_ERRORS.MISSING_FUTURE_DATE
            );
        }
        const calendar = helpers.getCalendar();
        const effectiveTimeZone = args.timeZone || defaultTimeZone;
        let eventData = originalEvent;
        if (!eventData) {
            const originalResponse = await calendar.events.get({
                calendarId: args.calendarId,
                eventId: args.eventId
            });
            eventData = originalResponse.data;
        }
        if (!eventData.recurrence) {
            throw new Error('Event does not have recurrence rules');
        }
        const untilDate = helpers.calculateUntilDate(args.futureStartDate);
        const updatedRecurrence = helpers.updateRecurrenceWithUntil(eventData.recurrence, untilDate);
        await calendar.events.patch({
            calendarId: args.calendarId,
            eventId: args.eventId,
            requestBody: { recurrence: updatedRecurrence }
        });
        const newStartTime = args.start || args.futureStartDate;
        const newEndTime = args.end || helpers.calculateEndTime(newStartTime, eventData);
        const newEvent = {
            ...helpers.cleanEventForDuplication(eventData),
            ...helpers.buildUpdateRequestBody(args, defaultTimeZone),
            start: createTimeObject(newStartTime, effectiveTimeZone),
            end: createTimeObject(newEndTime, effectiveTimeZone)
        };
        const response = await calendar.events.insert({
            calendarId: args.calendarId,
            requestBody: newEvent
        });
        if (!response.data) throw new Error('Failed to create new recurring event');
        return response.data;
    }
}import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { Client } from '@modelcontextprotocol/sdk/client/index.js';
import { StdioClientTransport } from '@modelcontextprotocol/sdk/client/stdio.js';
import { initializeOAuth2Client } from '../../auth/client.js';
import { TokenManager } from '../../auth/tokenManager.js';
import { TestDataFactory } from './test-data-factory.js';
import { getTextContent } from '../unit/helpers/content.js';
import {
  createAndVerifyEvent,
  updateAndVerifyEvent,
  createNonOverlappingEventPair,
  createOverlappingEventPair
} from './integration-test-helpers.js';
const ONE_HOUR_MS = 60 * 60 * 1000;
const ONE_DAY_MS = 24 * ONE_HOUR_MS;
const HALF_HOUR_MS = 30 * 60 * 1000;
describe('Conflict Detection Integration (MCP Protocol)', () => {
  let mcpClient: Client;
  const createdEventIds: string[] = [];
  const TEST_CALENDAR_ID = TestDataFactory.getTestCalendarId();
  beforeAll(async () => {
    const oauth2Client = await initializeOAuth2Client();
    const tokenManager = new TokenManager(oauth2Client);
    const isAuth = await tokenManager.isAuthenticated();
    if (!isAuth) {
      throw new Error(
        'No valid tokens found. Run: npm run auth\n' +
          'For integration tests with Doppler: ' +
          'doppler run --project integrity-studio --config dev -- npm run test:integration'
      );
    }
    const cleanEnv = Object.fromEntries(
      Object.entries(process.env).filter(([, value]) => value !== undefined)
    ) as Record<string, string>;
    cleanEnv.NODE_ENV = 'test';
    mcpClient = new Client(
      {
        name: 'conflict-detection-test',
        version: '1.0.0'
      },
      {
        capabilities: {}
      }
    );
    const transport = new StdioClientTransport({
      command: 'node',
      args: ['build/index.js'],
      env: cleanEnv
    });
    await mcpClient.connect(transport);
    const tools = await mcpClient.listTools();
    const toolNames = tools.tools.map((t) => t.name);
    expect(toolNames).toContain('create-event');
    expect(toolNames).toContain('update-event');
    expect(toolNames).toContain('delete-event');
    expect(toolNames).toContain('get-event');
  }, 30000);
  afterAll(async () => {
    const deleteResults = await Promise.allSettled(
      createdEventIds.map((eventId) =>
        mcpClient.callTool({
          name: 'delete-event',
          arguments: {
            calendarId: TEST_CALENDAR_ID,
            eventId
          }
        })
      )
    );
    deleteResults.forEach((result, idx) => {
      if (result.status === 'rejected') {
        console.warn(`Failed to cleanup event ${createdEventIds[idx]}:`, result.reason);
      }
    });
    if (mcpClient) {
      await mcpClient.close();
    }
  }, 30000);
  describe('Event Creation Without Conflicts', () => {
    it('should create non-overlapping events without conflict', async () => {
      const now = new Date();
      const { event1Id, event2Id } = await createNonOverlappingEventPair(
        mcpClient,
        TEST_CALENDAR_ID,
        now,
        createdEventIds
      );
      expect(event1Id).toBeTruthy();
      expect(event2Id).toBeTruthy();
    });
  });
  describe('Conflict Detection: Overlapping Times', () => {
    it('should detect overlap when updating event to conflict with existing', async () => {
      const now = new Date();
      const { event1Id, event2Id } = await createOverlappingEventPair(
        mcpClient,
        TEST_CALENDAR_ID,
        now,
        createdEventIds
      );
      const start1 = new Date(now.getTime() + 3 * ONE_HOUR_MS);
      const start2 = new Date(start1.getTime() + HALF_HOUR_MS);
      const end2 = new Date(start2.getTime() + ONE_HOUR_MS);
      const { text } = await updateAndVerifyEvent(
        mcpClient,
        TEST_CALENDAR_ID,
        event2Id,
        start2,
        end2,
        true
      );
      expect(text).toBeTruthy();
    });
  });
  describe('Conflict Detection: Non-Overlapping Times', () => {
    it('should not detect conflicts for truly non-overlapping events', async () => {
      const now = new Date();
      const { event1Id, event2Id } = await createNonOverlappingEventPair(
        mcpClient,
        TEST_CALENDAR_ID,
        now,
        createdEventIds
      );
      const start1 = new Date(now.getTime() + 4 * ONE_HOUR_MS);
      const end1 = new Date(start1.getTime() + ONE_HOUR_MS);
      const start2 = new Date(end1.getTime() + HALF_HOUR_MS);
      const end2 = new Date(start2.getTime() + ONE_HOUR_MS);
      const { text } = await updateAndVerifyEvent(
        mcpClient,
        TEST_CALENDAR_ID,
        event2Id,
        start2,
        end2,
        true
      );
      expect(text).toContain('No-Conflict Event 2');
    });
  });
  describe('Duplicate Detection', () => {
    it('should handle creation of similar events', async () => {
      const now = new Date();
      const start = new Date(now.getTime() + 5 * ONE_HOUR_MS);
      const end = new Date(start.getTime() + ONE_HOUR_MS);
      const { eventId: eventId1 } = await createAndVerifyEvent(
        mcpClient,
        TEST_CALENDAR_ID,
        'Duplicate Test Event',
        start,
        end,
        createdEventIds
      );
      expect(eventId1).toBeTruthy();
      const FIVE_MIN_MS = 5 * 60 * 1000;
      const start2 = new Date(start.getTime() + FIVE_MIN_MS);
      const end2 = new Date(end.getTime() + FIVE_MIN_MS);
      const { eventId: eventId2 } = await createAndVerifyEvent(
        mcpClient,
        TEST_CALENDAR_ID,
        'Duplicate Test Event',
        start2,
        end2,
        createdEventIds
      );
      expect(eventId2).toBeTruthy();
      expect(eventId1).not.toBe(eventId2);
    });
  });
  describe('Recurring Events and Conflict Detection', () => {
    it('should handle conflict detection with recurring events', async () => {
      const recurringEvent = TestDataFactory.createRecurringEvent({
        summary: 'Recurring Conflict Base'
      });
      const result1 = await mcpClient.callTool({
        name: 'create-event',
        arguments: {
          calendarId: TEST_CALENDAR_ID,
          ...recurringEvent
        }
      });
      const id = TestDataFactory.extractEventIdFromResponse(result1);
      if (id) createdEventIds.push(id);
      const now = new Date();
      const overlapStart = new Date(now.getTime() + ONE_DAY_MS);
      overlapStart.setUTCHours(11, 0, 0, 0);
      const { eventId: eventId2 } = await createAndVerifyEvent(
        mcpClient,
        TEST_CALENDAR_ID,
        'Overlaps Recurring Instance',
        overlapStart,
        new Date(overlapStart.getTime() + ONE_HOUR_MS),
        createdEventIds
      );
      expect(eventId2).toBeTruthy();
    });
  });
