export const RRULE_PATTERNS = {
  UNTIL: /;UNTIL=\d{8}T\d{6}Z/g,
  COUNT: /;COUNT=\d+/g,
  RRULE_PREFIX: /^RRULE:/,
  EXDATE: /^EXDATE:/,
