    }
    const updatedRecurrence: string[] = [];
    let foundRRule = false;
    for (const rule of recurrence) {
      if (isRRuleString(rule)) {
        foundRRule = true;
        const updatedRule = stripUntilAndCount(rule) + `;UNTIL=${untilDate}`;
        updatedRecurrence.push(updatedRule);
      } else {
